import {PRESETS} from '../state/texture-presets.js';import {RECIPES} from '../state/recipes.js';
export function attachControls(el,app){const btns=Object.keys(PRESETS).map(k=>`<button data-preset='${k}'>${k}</button>`).join('');const recipes=Object.keys(RECIPES).map(r=>`<option>${r}</option>`).join('');el.innerHTML=`<div class='row'><button id='min'>—</button><button id='pause'>pause</button><button id='perf'>perf</button><button id='copydbg'>copy debug</button><button id='copyset'>copy settings</button><button id='cap'>capture</button></div><div class='row'>${btns}</div><div class='row'>recipe <select id='recipe'>${recipes}</select> quality <select id='q'><option value='1'>1</option><option value='2' selected>2</option><option value='3'>3</option><option value='4'>4</option></select></div>`;
el.onclick=e=>{const p=e.target.dataset?.preset;if(p)app.setPreset(p);if(e.target.id==='min')el.classList.toggle('min');if(e.target.id==='pause')app.togglePause();if(e.target.id==='perf')app.togglePerf();if(e.target.id==='copydbg')navigator.clipboard?.writeText(JSON.stringify(window.tesseraDebug(),null,2));if(e.target.id==='copyset')navigator.clipboard?.writeText(JSON.stringify(app.state.intensity,null,2));if(e.target.id==='cap')app.capture();};el.querySelector('#recipe').onchange=e=>app.setRecipe(e.target.value);el.querySelector('#q').onchange=e=>app.setQuality(+e.target.value);}
